// main.js (The Main Thread)
const worker = new Worker('worker.js');

// Send data to the worker
worker.postMessage({ command: 'processData', data: [1, 2, 3, 4] });

// Listen for the result
worker.onmessage = function(e) {
  console.log('Worker finished processing:', e.data);
};


// worker.js (The Background Thread)
onmessage = function(e) {
  if (e.data.command === 'processData') {
    // Do heavy math here...
    const result = e.data.data.map(x => x * 1000000);

    // Send it back to the main thread
    postMessage(result);
  }
};
